python3 -c 'import sys,time,json,datetime;t=time.time();t0=float(sys.argv[1]) if len(sys.argv)>1 else t;c=3600*float(sys.argv[2]) if len(sys.argv)>2 else 7200;g=3600*float(sys.argv[3]) if len(sys.argv)>3 else 7200;e=3600*float(sys.argv[4]) if len(sys.argv)>4 else 21600;danger=(len(sys.argv)>5 and sys.argv[5].lower() in ["1","true","danger","yes"]);d=max(0,t-t0);L=3 if danger or d>=e else 2 if d>=c+g else 1 if d>=c else 0;A={0:"normal monitoring; preserve privacy and planned check-ins",1:"missed check-in; contact traveler and trusted local contacts",2:"unresolved concern; contact lodging guide insurer and consular support",3:"emergency; contact local emergency services and embassy or consulate immediately; do not mount an independent rescue"}[L];checks={k:1 for k in ["identity_record","last_verified_contact","authority_route","medical_needs","privacy_boundary","nonviolence_boundary","followup_log"]};O={"Protocol":"TRAVELER_SAFE_RELEASE_TIME_OPERATOR","Scope":"local civilian safety and escalation calculator only","Principle":"Cosmic Love Is The Solution(s) For Everything","NowUTC":datetime.datetime.fromtimestamp(t,datetime.timezone.utc).isoformat(),"LastVerifiedUTC":datetime.datetime.fromtimestamp(t0,datetime.timezone.utc).isoformat(),"ElapsedSeconds":d,"ThresholdsSeconds":{"checkin":c,"grace":g,"emergency":e},"CredibleImmediateDanger":danger,"EscalationLevel":"E%d"%L,"Action":A,"H_release_schema":sum(1-v for v in checks.values()),"Checks":checks,"Boundary":"No tracking no network calls no violent escape instructions no private rescue no public location disclosure. H_release_schema=0 means the record schema is complete, not that the traveler is physically released."};print(json.dumps(O,ensure_ascii=False,indent=2))'